from google.cloud import functions_v1
import pymysql
import os

def mysql_search(request):
    # Connection settings
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    db_connection_name = os.environ.get('DB_CONNECTION_NAME')

    if request.method == 'OPTIONS':
        headers = {
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Methods': 'POST',
            'Access-Control-Allow-Headers': 'Content-Type',
            'Access-Control-Max-Age': '3600'
        }
        return ('', 204, headers)

    headers = {'Access-Control-Allow-Origin': '*'}
    
    request_json = request.get_json(silent=True)
    if request_json and 'criteria' in request_json:
        criteria = request_json['criteria']
    else:
        criteria = {}

    try:
        connection = pymysql.connect(
            unix_socket=f'/cloudsql/{db_connection_name}',
            user=db_user,
            password=db_password,
            database=db_name
        )

        query = "SELECT * FROM your_table WHERE "
        where_clauses = []

        for key, value in criteria.items():
            where_clauses.append(f"{key} = '{value}'")

        query += " AND ".join(where_clauses) if where_clauses else "1"

        with connection.cursor() as cursor:
            cursor.execute(query)
            results = cursor.fetchall()

        return (results, 200, headers)
        
    except Exception as e:
        return (f"Error: {str(e)}", 500, headers)
    finally:
        connection.close()